args.sparql:
SELECT ?university ?campus ?universityLabel ?campusLabel WHERE {
  wd:Q4637473 wdt:P527 ?match .
  ?match wdt:P276 ?matchLocation .
  ?match ?p1 ?participation1 ;
         ?p2 ?participation2 .
  ?participation1 ps:P710 ?team1 ;
                  pq:P2503 ?score1 .
  ?participation2 ps:P710 ?team2 ;
                  pq:P2503 ?score2 .
  ?team1 wdt:P131 ?location1 .
  ?team2 wdt:P131 ?location2 .

  FILTER (?team1 != ?team2)
  FILTER ((?score1 = 85 && ?score2 = 15) || (?score1 = 15 && ?score2 = 85))

  FILTER (
    (?score2 = 15 && ?location2 != ?matchLocation && ?location1 = ?matchLocation) ||
    (?score1 = 15 && ?location1 != ?matchLocation && ?location2 = ?matchLocation)
  )

  BIND(IF(?score2 = 15 && ?location2 != ?matchLocation, ?team2, ?team1) AS ?awayTeam)

  ?awayTeam wdt:P1416 ?university .
  ?university wdt:P937 ?campus .

  OPTIONAL { ?university rdfs:label ?universityLabel FILTER(LANG(?universityLabel) = "en") }
  OPTIONAL { ?campus rdfs:label ?campusLabel FILTER(LANG(?campusLabel) = "en") }
}
